import{_ as e,c as i,o as r,a1 as n}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Cadena de herramientas: Verificación, compilación e integración CI | agent-skills","description":"Aprende a usar la cadena de herramientas de Agent Skills. Valida reglas, genera AGENTS.md, configura CI de GitHub Actions y extrae casos de prueba.","frontmatter":{"title":"Cadena de herramientas: Verificación, compilación e integración CI | agent-skills","sidebarTitle":"Cadena de herramientas","subtitle":"Cadena de herramientas: Verificación, compilación e integración CI","description":"Aprende a usar la cadena de herramientas de Agent Skills. Valida reglas, genera AGENTS.md, configura CI de GitHub Actions y extrae casos de prueba.","tags":["Herramientas de compilación","CI/CD","Automatización","Verificación de código"],"prerequisite":["start-getting-started","start-installation","advanced-rule-authoring"]},"headers":[],"relativePath":"es/vercel-labs/agent-skills/advanced/build-toolchain/index.md","filePath":"es/vercel-labs/agent-skills/advanced/build-toolchain/index.md"}'),t={name:"es/vercel-labs/agent-skills/advanced/build-toolchain/index.md"};function o(l,a,s,d,c,u){return r(),i("div",null,[...a[0]||(a[0]=[n('<h1 id="uso-de-la-cadena-de-herramientas-de-compilacion" tabindex="-1">Uso de la cadena de herramientas de compilación <a class="header-anchor" href="#uso-de-la-cadena-de-herramientas-de-compilacion" aria-label="Permalink to &quot;Uso de la cadena de herramientas de compilación&quot;">​</a></h1><h2 id="lo-que-podras-hacer-al-terminar" tabindex="-1">Lo que podrás hacer al terminar <a class="header-anchor" href="#lo-que-podras-hacer-al-terminar" aria-label="Permalink to &quot;Lo que podrás hacer al terminar&quot;">​</a></h2><p>Al terminar esta lección, podrás:</p><ul><li>✅ Usar <code>pnpm validate</code> para verificar el formato y la integridad de los archivos de reglas</li><li>✅ Usar <code>pnpm build</code> para generar AGENTS.md y test-cases.json</li><li>✅ Entender el flujo de compilación: parse → validate → group → sort → generate</li><li>✅ Configurar CI de GitHub Actions para verificación y compilación automática</li><li>✅ Extraer casos de prueba para evaluación automática de LLM</li><li>✅ Usar <code>pnpm dev</code> para el flujo de desarrollo rápido (build + validate)</li></ul><h2 id="tu-situacion-actual" tabindex="-1">Tu situación actual <a class="header-anchor" href="#tu-situacion-actual" aria-label="Permalink to &quot;Tu situación actual&quot;">​</a></h2><p>Si estás manteniendo o ampliando la biblioteca de reglas de React, puedes haber encontrado estos problemas:</p><ul><li>✗ Después de modificar reglas, olvidas verificar el formato, lo que provoca errores en AGENTS.md generado</li><li>✗ Hay cada vez más archivos de reglas, verificar manualmente la integridad de cada archivo es demasiado lento</li><li>✗ Solo después de enviar el código descubres que alguna regla carece de ejemplos de código, afectando la eficiencia de revisión de PR</li><li>✗ Quieres verificar automáticamente las reglas en CI, pero no sabes cómo configurar GitHub Actions</li><li>✗ No entiendes claramente el flujo de compilación de <code>build.ts</code>, no sabes por dónde empezar a solucionar errores</li></ul><h2 id="cuando-usar-esta-tecnica" tabindex="-1">Cuándo usar esta técnica <a class="header-anchor" href="#cuando-usar-esta-tecnica" aria-label="Permalink to &quot;Cuándo usar esta técnica&quot;">​</a></h2><p>Cuando necesitas:</p><ul><li>🔍 <strong>Verificar reglas</strong>: Asegurar antes de enviar código que todos los archivos de reglas cumplen con especificaciones</li><li>🏗️ <strong>Generar documentación</strong>: Generar AGENTS.md estructurado desde archivos de reglas Markdown</li><li>🤖 <strong>Extraer casos de prueba</strong>: Preparar datos de prueba para evaluación automática de LLM</li><li>🔄 <strong>Integrar CI</strong>: Automatizar verificación y compilación en GitHub Actions</li><li>🚀 <strong>Desarrollo rápido</strong>: Usar <code>pnpm dev</code> para iterar y verificar reglas rápidamente</li></ul>',10)])])}const g=e(t,[["render",o]]);export{m as __pageData,g as default};
